"use strict";

const fs = require("node:fs");
const path = require("node:path");

const projectRoot = path.resolve(__dirname, "..");
const entryFile = path.resolve(projectRoot, "src", "main.js");
const outputFile = path.resolve(projectRoot, "main.js");

const modules = new Map();
const visiting = new Set();

function toKey(absPath) {
  const rel = path.relative(projectRoot, absPath).replace(/\\/g, "/");
  return rel.replace(/\.js$/, "");
}

function resolveRelative(fromFile, request) {
  const fromDir = path.dirname(fromFile);
  let target = path.resolve(fromDir, request);
  if (path.extname(target) === ".js" && fs.existsSync(target)) return target;
  if (fs.existsSync(`${target}.js`)) return `${target}.js`;
  const indexCandidate = path.join(target, "index.js");
  if (fs.existsSync(indexCandidate)) return indexCandidate;
  throw new Error(`Cannot resolve "${request}" from ${fromFile}`);
}

const REQUIRE_RE = /require\(\s*(["'])(\.{1,2}\/[^"')\s]+)\1\s*\)/g;

function processFile(absPath) {
  const key = toKey(absPath);
  if (modules.has(key) || visiting.has(key)) return key;
  visiting.add(key);
  let source = fs.readFileSync(absPath, "utf8");
  source = source.replace(REQUIRE_RE, (_match, _quote, request) => {
    const resolved = resolveRelative(absPath, request);
    const childKey = processFile(resolved);
    return `__yd_require(${JSON.stringify(childKey)})`;
  });
  modules.set(key, source);
  visiting.delete(key);
  return key;
}

const entryKey = processFile(entryFile);

const banner = [
  "/* yori-dashboard bundle - generated by scripts/bundle.js */",
  '"use strict";',
  "var __yd_native_require = require;",
  "var __yd_modules = Object.create(null);",
  "var __yd_cache = Object.create(null);",
  "function __yd_require(id) {",
  "  if (Object.prototype.hasOwnProperty.call(__yd_cache, id)) {",
  "    return __yd_cache[id].exports;",
  "  }",
  "  var factory = __yd_modules[id];",
  "  if (typeof factory !== \"function\") {",
  "    return __yd_native_require(id);",
  "  }",
  "  var module = { exports: {} };",
  "  __yd_cache[id] = module;",
  "  factory.call(module.exports, module, module.exports, __yd_require);",
  "  return module.exports;",
  "}"
].join("\n");

const factories = [];
for (const [key, source] of modules.entries()) {
  factories.push(
    `__yd_modules[${JSON.stringify(key)}] = function(module, exports, require) {\n${source}\n};`
  );
}

const footer = [
  `var __yd_entry = __yd_require(${JSON.stringify(entryKey)});`,
  "module.exports = __yd_entry && __yd_entry.default ? __yd_entry.default : __yd_entry;",
  "module.exports.default = module.exports;"
].join("\n");

const output = [banner, "", factories.join("\n\n"), "", footer, ""].join("\n");
fs.writeFileSync(outputFile, output, "utf8");

const sizeKb = (Buffer.byteLength(output) / 1024).toFixed(1);
console.log(`bundled ${modules.size} modules → main.js (${sizeKb} KB)`);
